import anthropic

client = anthropic.Anthropic()

def budget_breakdown(
    system: str,
    tools: list[dict],
    messages: list[dict],
    model: str = "claude-haiku-4-5-20251001",
) -> dict:
    """Return token count for each context category."""
    base = client.messages.count_tokens(
        model=model, system=system, tools=tools, messages=[]
    ).input_tokens

    with_messages = client.messages.count_tokens(
        model=model, system=system, tools=tools, messages=messages
    ).input_tokens

    return {
        "system_and_tools": base,
        "conversation": with_messages - base,
        "total": with_messages,
    }

# Example usage
from anthropic.types import TextBlock
msgs = [
    {"role": "user", "content": "What is the weather in Tokyo?"},
    {"role": "assistant", "content": "Let me check that for you."},
]
system = "You are a helpful assistant with access to weather tools."
tools = [{"name": "get_weather", "description": "Get weather.", "input_schema": {
    "type": "object", "properties": {"city": {"type": "string"}}, "required": ["city"],
    "additionalProperties": False,
}}]
print(budget_breakdown(system, tools, msgs))
# {'system_and_tools': 80, 'conversation': 28, 'total': 108}
